import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import { useAuth } from "../context/AuthContext";
import axios from "axios";
import InternshipCard from "../components/InternshipCard";

export default function Internship() {
  const [internships, setInternships] = useState([]);
  const [searchTerm, setSearchTerm] = useState("");
  const [filterLocation, setFilterLocation] = useState("");
  const navigate = useNavigate();
  const { currentUser } = useAuth();

  const fetchInternships = async () => {
    try {
      const res = await axios.get("http://localhost:5000/api/internships");
      setInternships(res.data);
    } catch (err) {
      console.error("Failed to fetch internships", err);
    }
  };

  useEffect(() => {
    fetchInternships();
  }, []);

  const filteredInternships = internships.filter((internship) => {
    return (
      internship.title.toLowerCase().includes(searchTerm.toLowerCase()) &&
      (filterLocation === "" ||
        internship.location.toLowerCase().includes(filterLocation.toLowerCase()))
    );
  });

  return (
    <div className="internship-page" style={{ padding: "1.5rem" }}>
      <h2>Internships</h2>

      {/* ✅ Button only for Admin/HR */}
      {(currentUser?.role === "admin" || currentUser?.role === "hr") && (
        <div style={{ textAlign: "end", marginBottom: "1rem" }}>
          <button className="btn" onClick={() => navigate("/post-internship")}>
            + Post Internship
          </button>
        </div>
      )}

      {/* ✅ Filters */}
      <div style={{ display: "flex", gap: "1rem", marginBottom: "1rem" }}>
        <input
          type="text"
          placeholder="Search by title"
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
        />
        <input
          type="text"
          placeholder="Filter by location"
          value={filterLocation}
          onChange={(e) => setFilterLocation(e.target.value)}
        />
      </div>

      {/* ✅ Internship Cards */}
      <div className="internship-list" style={{ display: "grid", gap: "1rem" }}>
        {filteredInternships.length > 0 ? (
          filteredInternships.map((internship) => (
            <InternshipCard
              key={internship._id}
              internship={internship}
              onUpdate={fetchInternships}
            />
          ))
        ) : (
          <p>No internships found.</p>
        )}
      </div>
    </div>
  );
}
